using System;namespace BgCommon.Localization;/// <summary>/// 表示在执行本地化生成器期间发生的错误./// </summary>public class LocalizationBuilderException : Exception{    /// <summary>    /// Initializes a new instance of the <see cref="LocalizationBuilderException"/> class.    /// </summary>    /// <param name="message"> 描述错误的消息. </param>    public LocalizationBuilderException(string message)        : base(message)    {    }    /// <summary>    /// Initializes a new instance of the <see cref="LocalizationBuilderException"/> class.    /// </summary>    /// <param name="message"> 描述错误的消息. </param>    /// <param name="innerException"> 导致当前异常的异常. </param>    public LocalizationBuilderException(string message, Exception innerException)        : base(message, innerException)    {    }}